+package playback
+
+import (
+	"context"
+	"testing"
+
+	"github.com/navidrome/navidrome/model"
+	"github.com/navidrome/navidrome/tests"
+)
+
+func TestPlaybackServerUsesInjectedDatastoreBeforeRun(t *testing.T) {
+	ds := &tests.MockDataStore{}
+	ctx := context.Background()
+
+	if err := ds.MediaFile(ctx).Put(&model.MediaFile{ID: "track-1", Title: "Track 1"}); err != nil {
+		t.Fatalf("failed to seed media file: %v", err)
+	}
+
+	server, ok := GetInstance(ds).(*playbackServer)
+	if !ok {
+		t.Fatalf("expected playbackServer implementation")
+	}
+
+	mediaFile, err := server.GetMediaFile("track-1")
+	if err != nil {
+		t.Fatalf("expected media lookup to succeed before Run, got %v", err)
+	}
+	if mediaFile == nil || mediaFile.ID != "track-1" {
+		t.Fatalf("expected injected datastore media file, got %#v", mediaFile)
+	}
+}
