+	tests.MockDataStore
+}
+
+func (*scannerTestDataStore) MediaFolder(context.Context) model.MediaFolderRepository {
+	return testMediaFolderRepo{}
+}
+
+func expectScannerInitPanic(t *testing.T, invoke func()) {
+	t.Helper()
+
+	defer func() {
+		if r := recover(); r == nil {
+			t.Fatalf("expected mismatched scanner initialization to panic")
+		}
+	}()
+
+	invoke()
+}
+
+func TestGetScannerAppliesSingletonInitializationPolicy(t *testing.T) {
+	ds1 := &scannerTestDataStore{}
+	playlists1 := core.Playlists(&testPlaylists{id: "one"})
+	playlists2 := core.Playlists(&testPlaylists{id: "two"})
+	cacheWarmer1 := artwork.CacheWarmer(&testCacheWarmer{id: "one"})
+	cacheWarmer2 := artwork.CacheWarmer(&testCacheWarmer{id: "two"})
+	broker1 := events.Broker(&testBroker{id: "one"})
+	broker2 := events.Broker(&testBroker{id: "two"})
+
+	first := GetInstance(ds1, playlists1, cacheWarmer1, broker1)
+	second := GetInstance(ds1, playlists1, cacheWarmer1, broker1)
+	if first != second {
+		t.Fatalf("expected repeated calls with matching collaborators to return the same scanner instance")
+	}
+
+	expectScannerInitPanic(t, func() {
+		_ = GetInstance(&scannerTestDataStore{}, playlists1, cacheWarmer1, broker1)
+	})
+
+	expectScannerInitPanic(t, func() {
+		_ = GetInstance(ds1, playlists2, cacheWarmer1, broker1)
+	})
+
+	expectScannerInitPanic(t, func() {
+		_ = GetInstance(ds1, playlists1, cacheWarmer2, broker1)
+	})
+
+	expectScannerInitPanic(t, func() {
+		_ = GetInstance(ds1, playlists1, cacheWarmer1, broker2)
+	})
+}
