@@ -0,0 +1,106 @@
+package subsonic
+
+import (
+	"context"
+	"testing"
+	"time"
+
+	"github.com/navidrome/navidrome/conf"
+	"github.com/navidrome/navidrome/core/playback"
+	"github.com/navidrome/navidrome/model"
+	"github.com/navidrome/navidrome/model/request"
+	"github.com/navidrome/navidrome/tests"
+)
+
+func TestSubsonicApiAllowsUnrelatedRoutesWithoutPlayback(t *testing.T) {
+	previousEnabled := conf.Server.Jukebox.Enabled
+	previousAdminOnly := conf.Server.Jukebox.AdminOnly
+	t.Cleanup(func() {
+		conf.Server.Jukebox.Enabled = previousEnabled
+		conf.Server.Jukebox.AdminOnly = previousAdminOnly
+	})
+
+	conf.Server.Jukebox.Enabled = true
+	conf.Server.Jukebox.AdminOnly = false
+
+	router := New(&tests.MockDataStore{}, nil, nil, nil, nil, nil, nil, nil, nil, nil, nil, nil)
+
+	response, err := router.Ping(newGetRequest())
+	if err != nil {
+		t.Fatalf("expected non-jukebox route to work without playback even when jukebox is enabled, got %v", err)
+	}
+	if response == nil {
+		t.Fatalf("expected ping response")
+	}
+}
+
+func TestJukeboxControlUsesInjectedPlaybackDependency(t *testing.T) {
+	ds := &tests.MockDataStore{}
+	previousEnabled := conf.Server.Jukebox.Enabled
+	previousAdminOnly := conf.Server.Jukebox.AdminOnly
+	previousDefault := conf.Server.Jukebox.Default
+	previousDevices := append([]conf.AudioDeviceDefinition(nil), conf.Server.Jukebox.Devices...)
+
+	t.Cleanup(func() {
+		conf.Server.Jukebox.Enabled = previousEnabled
+		conf.Server.Jukebox.AdminOnly = previousAdminOnly
+		conf.Server.Jukebox.Default = previousDefault
+		conf.Server.Jukebox.Devices = previousDevices
+	})
+
+	conf.Server.Jukebox.Enabled = true
+	conf.Server.Jukebox.AdminOnly = false
+	conf.Server.Jukebox.Default = "primary"
+	conf.Server.Jukebox.Devices = []conf.AudioDeviceDefinition{{"primary", "Primary Device"}}
+
+	playbackServer := playback.GetInstance(ds)
+	runCtx, cancel := context.WithCancel(context.Background())
+	runDone := make(chan error, 1)
+	go func() {
+		runDone <- playbackServer.Run(runCtx)
+	}()
+	t.Cleanup(func() {
+		cancel()
+		select {
+		case err := <-runDone:
+			if err != nil {
+				t.Fatalf("playback server stopped with error: %v", err)
+			}
+		case <-time.After(time.Second):
+			t.Fatalf("timed out waiting for playback server shutdown")
+		}
+	})
+
+	waitForPlaybackServer(t, playbackServer)
+
+	req := newGetRequest("action=status")
+	req = req.WithContext(request.WithUser(req.Context(), model.User{UserName: "alice"}))
+
+	routerWithoutPlayback := New(ds, nil, nil, nil, nil, nil, nil, nil, nil, nil, nil, nil)
+	if _, err := routerWithoutPlayback.JukeboxControl(req); err == nil {
+		t.Fatalf("expected jukebox control to fail without an injected playback service")
+	}
+
+	routerWithPlayback := New(ds, nil, nil, nil, nil, nil, nil, nil, nil, nil, nil, playbackServer)
+	response, err := routerWithPlayback.JukeboxControl(req)
+	if err != nil {
+		t.Fatalf("expected injected playback service to satisfy jukebox control, got %v", err)
+	}
+	if response == nil || response.JukeboxStatus == nil {
+		t.Fatalf("expected jukebox status response")
+	}
+}
+
+func waitForPlaybackServer(t *testing.T, playbackServer playback.PlaybackServer) {
+	t.Helper()
+
+	deadline := time.Now().Add(2 * time.Second)
+	for time.Now().Before(deadline) {
+		if _, err := playbackServer.GetDeviceForUser("probe"); err == nil {
+			return
+		}
+		time.Sleep(10 * time.Millisecond)
+	}
+
+	t.Fatalf("playback server did not become ready")
+}
